function WebhookListener() {
  const [events, setEvents] = React.useState([]);
  const [error, setError] = React.useState('');
  const [paused, setPaused] = React.useState(false);
  const [path, setPath] = React.useState('REPLACE_WITH_PATH');
  React.useEffect(() => {
    if (paused) return;
    let alive = true;
    const tick = async () => {
      try {
        const url = path ? `/api/webhook/recent?path=${encodeURIComponent(path)}` : '/api/webhook/recent';
        const r = await titan.api.call(url, { method: 'GET' });
        if (!alive) return;
        const list = Array.isArray(r) ? r : (r?.events || []);
        setEvents(list.slice(0, 50));
        setError('');
      } catch (e) { setError(String(e?.message || e)); }
    };
    tick();
    const id = setInterval(tick, 3000);
    return () => { alive = false; clearInterval(id); };
  }, [paused, path]);
  return (
    <div style={{padding:12,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',gap:8,alignItems:'center',marginBottom:10}}>
        <input value={path} onChange={e=>setPath(e.target.value)} placeholder="Filter path (optional)"
          style={{flex:1,padding:'6px 10px',border:'1px solid #ccc',borderRadius:6,fontSize:13}}/>
        <button onClick={()=>setPaused(!paused)} style={{padding:'6px 12px',borderRadius:6,border:'1px solid #ccc',background:paused?'#FF9500':'#34C759',color:'#fff',cursor:'pointer'}}>{paused?'Resume':'Pause'}</button>
      </div>
      {error && <div style={{color:'#FF3B30',fontSize:12,marginBottom:6}}>⚠ {error}</div>}
      <div style={{flex:1,overflow:'auto',background:'#f9f9f9',borderRadius:8,padding:8}}>
        {events.length === 0 ? <div style={{textAlign:'center',color:'#888',padding:30}}>No events yet — POST to /api/webhook to send one.</div> :
          events.map((e,i)=>(
            <div key={i} style={{padding:8,marginBottom:6,background:'#fff',borderRadius:6,boxShadow:'0 1px 2px rgba(0,0,0,0.05)'}}>
              <div style={{display:'flex',gap:8,alignItems:'center',fontSize:12}}>
                <span style={{padding:'2px 8px',borderRadius:4,background:'#007AFF',color:'#fff',fontWeight:600}}>{e.method||'POST'}</span>
                <span style={{fontFamily:'monospace'}}>{e.path||'/'}</span>
                <span style={{marginLeft:'auto',color:'#888'}}>{e.ts ? new Date(e.ts).toLocaleTimeString() : ''}</span>
              </div>
              <pre style={{margin:'6px 0 0',fontSize:11,color:'#333',whiteSpace:'pre-wrap',wordBreak:'break-word',maxHeight:100,overflow:'auto'}}>{typeof e.body==='string' ? e.body : JSON.stringify(e.body||{},null,2)}</pre>
            </div>
          ))
        }
      </div>
    </div>
  );
}
render(<WebhookListener/>);
